using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: Cosmos DB provider no longer supports indexing.
        // modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
        // Manage indexes directly via Cosmos DB indexing policy instead.

        // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
        // To remain compatible with existing documents, restore the old property name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change 3: Id format changed from "EntityType|Key" to just "Key".
        // To remain compatible with existing documents using "Blog|1" format,
        // opt back in to the legacy id format.
        modelBuilder.Entity<Blog>(b =>
        {
            b.HasPartitionKey(x => x.Id);
            b.Property(x => x.Id)
             .HasJsonPropertyName("id");
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Breaking change 4: Sync I/O now throws by default.
        // SyncJob.cs uses synchronous .ToList() and .SaveChanges().
        // Either convert to async or opt in to sync I/O.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

