        // FIX: Manage indexes via the Cosmos DB indexing policy directly.

        // BREAKING CHANGE 2 — Discriminator property renamed: "Discriminator" → "$type".
        // Existing documents have { "Discriminator": "Blog" }.
        // FIX: Explicitly keep the old property name.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

