        // so EF9 can still read/write existing documents.
        modelBuilder.Entity<Blog>().Property(b => b.Id)
            .HasConversion(
                key => $"Blog|{key}",
                id  => id.Contains('|') ? id.Substring(id.IndexOf('|') + 1) : id);
    }
}
